"use client";

import React, { useState } from "react";
import { useSubsystemRegistrationFetchContext } from "../providers/fetchProvider";
import { SubsystemRegistration } from "../types";
import { toast } from "sonner";

export function useSubsystemRegistration() {
    const { subsystems, isLoading, addResource, updateResource, removeResource } = useSubsystemRegistrationFetchContext();
    
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [isHierarchyOpen, setIsHierarchyOpen] = useState(false);
    const [selectedSubsystem, setSelectedSubsystem] = useState<SubsystemRegistration | null>(null);
    const [hierarchySubsystem, setHierarchySubsystem] = useState<SubsystemRegistration | null>(null);

    const handleAdd = () => {
        setSelectedSubsystem(null);
        setIsDialogOpen(true);
    };

    const handleEdit = (subsystem: SubsystemRegistration) => {
        setSelectedSubsystem(subsystem);
        setIsDialogOpen(true);
    };

    const handleManageHierarchy = (subsystem: SubsystemRegistration) => {
        setHierarchySubsystem(subsystem);
        setIsHierarchyOpen(true);
    };

    const handleUpdateHierarchy = async (updated: SubsystemRegistration) => {
        const success = await updateResource(String(updated.id), updated);
        if (success) {
            toast.success(`Updated hierarchy for ${updated.title}`);
            return true;
        } else {
            toast.error("Failed to update hierarchy");
            return false;
        }
    };

    const handleDelete = async (subsystem: SubsystemRegistration) => {
        if (confirm(`Are you sure you want to delete ${subsystem.title}?`)) {
            const success = await removeResource(String(subsystem.id));
            if (success) {
                toast.success(`Subsystem ${subsystem.title} deleted.`);
            } else {
                toast.error("Failed to delete subsystem");
            }
        }
    };

    const handleSubmit = async (data: Partial<SubsystemRegistration>) => {
        if (selectedSubsystem) {
            // Edit
            const success = await updateResource(String(selectedSubsystem.id), data);
            if (success) {
                toast.success(`Updated ${data.title}`);
                return true;
            } else {
                toast.error(`Failed to update ${data.title}`);
                return false;
            }
        } else {
            // Add
            const success = await addResource(data);
            if (success) {
                toast.success(`Registered ${data.title}`);
                return true;
            } else {
                toast.error(`Failed to register ${data.title}`);
                return false;
            }
        }
    };

    return {
        subsystems,
        isLoading,
        isDialogOpen,
        setIsDialogOpen,
        isHierarchyOpen,
        setIsHierarchyOpen,
        selectedSubsystem,
        hierarchySubsystem,
        handleAdd,
        handleEdit,
        handleDelete,
        handleManageHierarchy,
        handleUpdateHierarchy,
        handleSubmit,
    };
}

import { SubsystemRegistration } from "../types";

export class SubsystemService {
    static async getSubsystems(): Promise<SubsystemRegistration[]> {
        try {
            // Fetch everything in parallel for speed
            const [subRes, modRes] = await Promise.all([
                fetch(`/api/hrm/subsystems?limit=-1`),
                fetch(`/api/hrm/modules?limit=-1`)
            ]);

            if (!subRes.ok || !modRes.ok) return [];

            const { data: subsystems } = await subRes.json();
            const { data: allModules } = await modRes.json();

            // 1. Build a map of modules by their subsystem_id
            const modulesBySubsystem: Record<number, any[]> = {};
            const modulesById: Record<number, any> = {};

            (allModules || []).forEach((m: any) => {
                const mod = { ...m, subModules: [] };
                modulesById[mod.id] = mod;
                
                const sid = Number(m.subsystem_id);
                if (!modulesBySubsystem[sid]) modulesBySubsystem[sid] = [];
                modulesBySubsystem[sid].push(mod);
            });

            // 2. Build the recursive tree for each subsystem
            const finalSubsystems = (subsystems || []).map((sub: any) => {
                const subId = Number(sub.id);
                const subModules = modulesBySubsystem[subId] || [];
                
                // Identify root modules (those with no parent_module_id)
                const roots = subModules.filter(m => !m.parent_module_id);
                
                // Link children to parents
                subModules.forEach(m => {
                    if (m.parent_module_id && modulesById[m.parent_module_id]) {
                        modulesById[m.parent_module_id].subModules.push(m);
                    }
                });

                return {
                    ...sub,
                    modules: roots
                };
            });

            return finalSubsystems;
        } catch (error) {
            console.error("Error in manual getSubsystems:", error);
            return [];
        }
    }

    /**
     * Recursively syncs modules and sub-modules to the database.
     * Handles both new items (POST) and updates (PATCH).
     */
    private static async syncModulesRecursively(
        modules: any[], 
        subsystemId: number, 
        parentId: number | null = null
    ): Promise<void> {
        for (const module of modules) {
            const isNew = !module.id || isNaN(Number(module.id)) || String(module.id).length > 5;
            
            // Prepare payload
            const payload: any = {
                slug: module.slug || "",
                title: module.title || "Untitled",
                base_path: module.base_path || "",
                status: module.status || "active",
                icon_name: module.icon_name || "Folder",
                subsystem_id: subsystemId,
                parent_module_id: parentId
            };

            let savedModuleId = module.id;

            try {
                if (isNew) {
                    // Create new module
                    const response = await fetch(`/api/hrm/modules`, {
                        method: "POST",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify(payload)
                    });
                    if (response.ok) {
                        const { data } = await response.json();
                        savedModuleId = data.id;
                    }
                } else {
                    // Update existing module
                    await fetch(`/api/hrm/modules?id=${module.id}`, {
                        method: "PATCH",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify(payload)
                    });
                }

                // Recursively sync sub-modules if any
                if (module.subModules && module.subModules.length > 0 && savedModuleId) {
                    await this.syncModulesRecursively(module.subModules, subsystemId, Number(savedModuleId));
                }
            } catch (err) {
                console.error(`Failed to sync module: ${module.title}`, err);
            }
        }
    }

    static async createSubsystem(data: Partial<SubsystemRegistration>): Promise<SubsystemRegistration | null> {
        try {
            // New subsystems shouldn't have ID yet
            const cleanedData = { ...data };
            delete cleanedData.id;
            delete cleanedData.modules; // Modules saved via sync

            const response = await fetch(`/api/hrm/subsystems`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(cleanedData)
            });
            
            if (!response.ok) return null;
            
            const { data: created } = await response.json();
            
            // Sync modules if any were provided
            if (data.modules && data.modules.length > 0) {
                await this.syncModulesRecursively(data.modules, Number(created.id));
            }

            return created;
        } catch (error) {
            console.error("Error creating subsystem:", error);
            return null;
        }
    }

    static async updateSubsystem(id: string, data: Partial<SubsystemRegistration>): Promise<boolean> {
        try {
            const subsystemId = Number(id);
            const subsystemPayload = { ...data };
            delete subsystemPayload.modules; // Modules saved via explicit sync

            // 1. Update the subsystem record
            const response = await fetch(`/api/hrm/subsystems?id=${id}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(subsystemPayload)
            });

            // 2. Sync Hierarchy (Modules and Sub-modules)
            if (data.modules) {
                await this.syncModulesRecursively(data.modules, subsystemId);
            }

            return response.ok;
        } catch (error) {
            console.error("Error updating subsystem:", error);
            return false;
        }
    }

    static async deleteSubsystem(id: string): Promise<boolean> {
        try {
            const response = await fetch(`/api/hrm/subsystems?id=${id}`, {
                method: "DELETE"
            });
            return response.ok;
        } catch (error) {
            console.error("Error deleting subsystem:", error);
            return false;
        }
    }

    /** @deprecated Use createSubsystem, updateSubsystem, or deleteSubsystem instead */
    static async saveSubsystems(subsystems: SubsystemRegistration[]): Promise<void> {
        console.warn("saveSubsystems is slow and deprecated. System is migrating to granular CRUD.");
    }
}

"use client";

import React from "react";
import {
    flexRender,
    getCoreRowModel,
    getFilteredRowModel,
    getSortedRowModel,
    useReactTable,
    type ColumnFiltersState,
    type SortingState,
} from "@tanstack/react-table";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Search } from "lucide-react";
import { cn } from "@/lib/utils";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import { UserSubsystemAccess } from "../types";
import { createColumns } from "./columns";
import { SubsystemRegistration } from "@/modules/human-resource-management/subsystem-registration/types";
import { TooltipProvider } from "@/components/ui/tooltip";

interface UserConfigurationTableProps {
    data: UserSubsystemAccess[];
    subsystems: SubsystemRegistration[];
    onToggleAccess: (userId: string, subsystemId: string, authorized: boolean) => void;
    onConfigure: (user: UserSubsystemAccess, subsystem: SubsystemRegistration) => void;
    isLoading?: boolean;
    currentPage: number;
    totalCount: number;
    pageSize: number;
    onPageChange: (page: number) => void;
}

export function UserConfigurationTable({
    data,
    subsystems,
    onToggleAccess,
    onConfigure,
    isLoading = false,
    currentPage,
    totalCount,
    pageSize,
    onPageChange,
}: UserConfigurationTableProps) {
    const [sorting, setSorting] = React.useState<SortingState>([]);
    const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>([]);

    const columns = React.useMemo(() => createColumns(subsystems, onToggleAccess, onConfigure), [subsystems, onToggleAccess, onConfigure]);

    const table = useReactTable({
        data,
        columns,
        onSortingChange: setSorting,
        onColumnFiltersChange: setColumnFilters,
        getCoreRowModel: getCoreRowModel(),
        getSortedRowModel: getSortedRowModel(),
        getFilteredRowModel: getFilteredRowModel(),
        state: {
            sorting,
            columnFilters,
        },
    });

    const totalPages = Math.ceil(totalCount / pageSize);

    if (isLoading) {
        return (
            <div className="space-y-4">
                <div className="h-10 bg-gray-200 rounded-xl animate-pulse" />
                <div className="rounded-2xl border">
                    <div className="h-96 bg-gray-100 animate-pulse" />
                </div>
            </div>
        );
    }

    return (
        <TooltipProvider>
            <div className="space-y-6">
                <div className="flex items-center justify-between gap-4">
                    <div className="relative group flex-1 max-sm">
                        <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground/60 transition-colors group-focus-within:text-primary" />
                        <Input
                            placeholder="Search users by name or email..."
                            value={(table.getColumn("full_name")?.getFilterValue() as string) ?? ""}
                            onChange={(event) =>
                                table.getColumn("full_name")?.setFilterValue(event.target.value)
                            }
                            className="pl-10 h-11 rounded-2xl bg-muted/20 border-muted-foreground/10 focus-visible:ring-primary/20 transition-all font-medium"
                        />
                    </div>
                </div>

                <div className="rounded-[2.5rem] border bg-card shadow-2xl shadow-primary/5 overflow-hidden">
                    <ScrollArea className="w-full">
                        <Table className="relative">
                            <TableHeader className="bg-muted/30 sticky top-0 z-10 backdrop-blur-md">
                                {table.getHeaderGroups().map((headerGroup) => (
                                    <TableRow key={headerGroup.id} className="hover:bg-transparent border-b-muted-foreground/10">
                                        {headerGroup.headers.map((header, index) => (
                                            <TableHead 
                                                key={header.id} 
                                                className={cn(
                                                    "h-14 font-black text-center border-r-[1px] border-muted-foreground/10 last:border-r-0",
                                                    index === 0 && "sticky left-0 bg-muted/80 z-20 text-left border-r-2"
                                                )}
                                            >
                                                {header.isPlaceholder
                                                    ? null
                                                    : flexRender(
                                                        header.column.columnDef.header,
                                                        header.getContext()
                                                    )}
                                            </TableHead>
                                        ))}
                                    </TableRow>
                                ))}
                            </TableHeader>
                            <TableBody>
                                {table.getRowModel().rows?.length ? (
                                    table.getRowModel().rows.map((row) => (
                                        <TableRow key={row.id} className="hover:bg-primary/[0.01] transition-colors border-b-muted-foreground/5 last:border-b-0">
                                            {row.getVisibleCells().map((cell, index) => (
                                                <TableCell 
                                                    key={cell.id}
                                                    className={cn(
                                                        "py-3 border-r-[1px] border-muted-foreground/5 last:border-r-0",
                                                        index === 0 && "sticky left-0 bg-card z-20 shadow-[4px_0_10px_-5px_rgba(0,0,0,0.1)] border-r-2"
                                                    )}
                                                >
                                                    {flexRender(cell.column.columnDef.cell, cell.getContext())}
                                                </TableCell>
                                            ))}
                                        </TableRow>
                                    ))
                                ) : (
                                    <TableRow>
                                        <TableCell colSpan={table.getAllColumns().length} className="h-40 text-center">
                                            <div className="flex flex-col items-center justify-center text-muted-foreground/60">
                                                <Search className="h-10 w-10 mb-2 opacity-20" />
                                                <p className="font-bold">No matching users found.</p>
                                            </div>
                                        </TableCell>
                                    </TableRow>
                                )}
                            </TableBody>
                        </Table>
                        <ScrollBar orientation="horizontal" />
                    </ScrollArea>
                </div>

                <div className="flex items-center justify-between bg-muted/10 p-4 rounded-3xl border border-muted-foreground/5">
                    <div className="flex items-center gap-2 text-[11px] font-bold uppercase tracking-widest text-muted-foreground/60">
                        <span className="bg-primary/10 text-primary px-2 py-0.5 rounded-md">{totalCount}</span>
                        Total Users Active
                    </div>
                    <div className="flex items-center gap-3">
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => onPageChange(currentPage - 1)}
                            disabled={currentPage === 0}
                            className="rounded-xl px-4 font-bold text-xs gap-2"
                        >
                            Previous
                        </Button>
                        <div className="text-[10px] font-mono text-muted-foreground/60">
                            Page {currentPage + 1} of {Math.max(1, totalPages)}
                        </div>
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => onPageChange(currentPage + 1)}
                            disabled={currentPage + 1 >= totalPages}
                            className="rounded-xl px-4 font-bold text-xs gap-2"
                        >
                            Next
                        </Button>
                    </div>
                </div>
            </div>
        </TooltipProvider>
    );
}

"use client";

import React, { useState, useCallback } from "react";
import { useUserConfigurationFetchContext } from "../providers/fetchProvider";
import { UserSubsystemAccess } from "../types";
import { SubsystemRegistration } from "@/modules/human-resource-management/subsystem-registration/types";
import { UserService } from "../services/UserService";
import { extractAllSlugs } from "../utils/permissionUtils";
import { toast } from "sonner";

export function useUserConfiguration() {
    const { 
        users, 
        subsystems, 
        isLoading, 
        currentPage, 
        totalCount, 
        pageSize, 
        fetchPage,
        updateUserPermissions,
    } = useUserConfigurationFetchContext();
    
    // Permissions Dialog State
    const [isPermissionsOpen, setIsPermissionsOpen] = useState(false);
    const [activeUser, setActiveUser] = useState<UserSubsystemAccess | null>(null);
    const [activeSubsystem, setActiveSubsystem] = useState<SubsystemRegistration | null>(null);

    const handleToggleAccess = useCallback(async (userId: string, subsystemId: string, authorized: boolean) => {
        let finalAccess: string[] = [];
        
        // Find the full subsystem object to get its children slugs
        const fullSubsystem = subsystems.find(s => s.slug === subsystemId);
        const slugsToToggle = fullSubsystem ? extractAllSlugs(fullSubsystem) : [subsystemId];

        const user = users.find(u => u.user_id === userId);
        if (!user) return;

        const newAccess = authorized
            ? Array.from(new Set([...user.authorized_subsystems, ...slugsToToggle]))
            : user.authorized_subsystems.filter((id) => !slugsToToggle.includes(id));
        
        finalAccess = newAccess;
        updateUserPermissions(userId, newAccess);

        // Persist change
        const success = await UserService.updatePermissions(userId, finalAccess);
        if (success) {
            toast.success(`Updated access for user ${userId}`);
        } else {
            toast.error("Failed to persist permission changes.");
        }
    }, [subsystems, users, updateUserPermissions]);

    const handleConfigure = useCallback((user: UserSubsystemAccess, subsystem: SubsystemRegistration) => {
        setActiveUser(user);
        setActiveSubsystem(subsystem);
        setIsPermissionsOpen(true);
    }, []);

    const handleUpdatePermissions = useCallback(async (userId: string, items: string[]) => {
        updateUserPermissions(userId, items);
        
        // Persist change
        const success = await UserService.updatePermissions(userId, items);
        if (success) {
            toast.success("Granular permissions updated successfully");
        } else {
            toast.error("Failed to persist granular changes.");
        }
    }, [updateUserPermissions]);

    return {
        users,
        subsystems,
        isLoading,
        currentPage,
        totalCount,
        pageSize,
        isPermissionsOpen,
        setIsPermissionsOpen,
        activeUser,
        activeSubsystem,
        fetchPage,
        handleToggleAccess,
        handleConfigure,
        handleUpdatePermissions,
    };
}
